#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int a,b; double r; if(scanf("%d %d %lf",&a,&b,&r)!=3) return 0;
        printf("%d\n", a*a);
        printf("%d\n", 6*b*b);
        printf("%.5f\n", acos(-1.0)*r*r);
    }
    return 0;
}

